module top_module(addr_out_invalid, w_bus_addr_in, w_clock, w_reset);input [7:0] w_bus_addr_in;				
	input w_clock, w_reset;					

	output reg [7:0] addr_out_invalid;			

	always @ (posedge w_clock)				
		if (w_reset) addr_out_invalid <= 8'b0;		
		else addr_out_invalid <= w_bus_addr_in;		
endmodule
